const item = $input.first().json;
let parsedQuery = {};
if (item.query) {
  try {
    parsedQuery = JSON.parse(item.query);
  } catch (e) {
    parsedQuery = { prompt: item.query };
  }
}

const body = item.body || item;
const params = body.params || body;
const fileId = parsedQuery.photo_file_id || parsedQuery.file_id || params.photo_file_id || params.file_id || body.photo_file_id || body.file_id || '';
const caption = parsedQuery.prompt || parsedQuery.caption || params.photo_caption || params.caption || params.prompt || body.photo_caption || body.caption || body.prompt || '';
const chatId = parsedQuery.chat_id || parsedQuery.chatId || params.photo_chat_id || params.chat_id || params.chatId || body.photo_chat_id || body.chat_id || body.chatId || '';

if (!fileId) {
  throw new Error('Không tìm thấy file_id ảnh sản phẩm. Vui lòng gửi ảnh kèm caption mô tả.');
}

return [{
  json: {
    file_id: fileId,
    caption: caption,
    chat_id: String(chatId),
    source: parsedQuery.source || params.source || body.source || 'telegram'
  }
}];

// Read binary via RPC helper, build Gemini request
const request = $node['Normalize Fashion Request'].json;
const chatId = request.chat_id;
const caption = request.caption || '';

// Get binary buffer via n8n RPC (resolves filesystem-v2 refs)
const binaryKey = Object.keys($input.first().binary || {})[0] || 'data';
const buffer = await helpers.getBinaryDataBuffer(0, binaryKey);
const photoBase64 = buffer.toString('base64');

// Detect MIME from base64 magic bytes
let photoMime = 'image/jpeg';
if (photoBase64.startsWith('/9j/')) photoMime = 'image/jpeg';
else if (photoBase64.startsWith('iVBOR')) photoMime = 'image/png';
else if (photoBase64.startsWith('R0lG')) photoMime = 'image/gif';
else if (photoBase64.startsWith('UklG')) photoMime = 'image/webp';

if (!photoBase64 || photoBase64.length < 100) {
  return [{ json: { success: false, chat_id: chatId, error_message: 'Binary buffer empty.' } }];
}

// Detect context from caption
const wantsModel = /người mẫu|model|mặc|wear|trên người/i.test(caption);
const wantsWhite = /nền trắng|white bg|studio trắng|nền sạch/i.test(caption);
const wantsLifestyle = /lifestyle|đời thường|outdoor|ngoài trời|phố|café|biển|park/i.test(caption);
const wantsFlatlay = /flat.?lay|treo|mannequin|ma.?nơ.?canh|ghost/i.test(caption);
const cleanCaption = caption.replace(/^🎨\s*(Tạo ảnh AI|tạo ảnh)\s*/i, '').trim();

// Extract aspect ratio from caption if specified. Default to 3:4 for model, 1:1 for flatlay
const ratioMatch = caption.match(/(1:1|3:4|4:5|9:16|16:9|2:3|3:2)/);
const aspectRatio = ratioMatch ? ratioMatch[0] : '1:1';

// Map to Gemini API AspectRatio Enum
const ratioMap = {
  '1:1': 'ASPECT_RATIO_ONE_BY_ONE',
  '3:4': 'ASPECT_RATIO_THREE_BY_FOUR',
  '4:3': 'ASPECT_RATIO_FOUR_BY_THREE',
  '9:16': 'ASPECT_RATIO_NINE_BY_SIXTEEN',
  '16:9': 'ASPECT_RATIO_SIXTEEN_BY_NINE',
  '2:3': 'ASPECT_RATIO_TWO_BY_THREE',
  '3:2': 'ASPECT_RATIO_THREE_BY_TWO',
  '4:5': 'ASPECT_RATIO_FOUR_BY_FIVE',
  '5:4': 'ASPECT_RATIO_FIVE_BY_FOUR'
};
const geminiAspectRatio = ratioMap[aspectRatio] || 'ASPECT_RATIO_ONE_BY_ONE';

// Build prompt — following Gemini's official "Advanced composition" pattern with strict humanization
const p = [];

if (wantsFlatlay) {
  // Flat lay / ghost mannequin mode
  p.push('Create a professional e-commerce clothing product photo. Take the clothing garment from the reference image and display it on an invisible ghost mannequin or as a premium styled flat lay, showing the complete shape, drape, and fit of the garment.');
  p.push('The output must be a COMPLETELY NEW professional product photograph showing the garment displayed cleanly.');
} else {
  // Default: Model wearing the product
  p.push('Create a professional e-commerce fashion photo. Take the clothing product from the reference image and generate a NEW photo of a professional model wearing this exact garment.');
  p.push('Generate a realistic, full-body shot of the model wearing the product. The model should have a natural, relaxed, and confident pose with a candid, pleasant facial expression.');

  // Product integrity constraint
  p.push('CRITICAL REQUIREMENT: The clothing on the model must remain 100% faithful to the reference image. The exact cut, folds, print patterns, logo placement, fabric texture, and color values of the clothing must be preserved perfectly. Do not simplify or alter the design.');
}

// Background & Lighting
if (wantsLifestyle) {
  p.push('Set the scene in a modern minimalist café with large glass windows letting in soft natural daylight, or a stylish urban street sidewalk in Vietnam, with soft background blur (bokeh) to keep focus on the subject. Adjust lighting, shadows, and highlights on the model to match this environment naturally.');
} else if (wantsWhite) {
  p.push('Use a pure white seamless studio background with clean, even professional lighting and minimal soft shadows under the feet/garment.');
} else {
  p.push('Use a clean studio background with a soft warm gradient from off-white to light gray. Professional fashion photography lighting setup with soft shadows.');
}

// Seller custom instructions
if (cleanCaption && cleanCaption.length > 3) {
  p.push('Additional seller requirements: ' + cleanCaption);
}

// Photographic style & quality parameters (Humanization)
p.push('Style and Technique: Captured with a DSLR 35mm lens, natural depth of field, subtle film grain/sensor noise for high realism. Beautiful natural textures on skin and hair, avoiding artificial porcelain skin look. One single fashion photograph with sharp focus. No text overlay, watermark, price tag, or graphic elements.');

return [{
  json: {
    chat_id: chatId,
    clean_caption: cleanCaption,
    gemini_body: {
      contents: [{
        role: 'user',
        parts: [
          { inline_data: { mime_type: photoMime, data: photoBase64 } },
          { text: p.join('\n\n') }
        ]
      }],
      generationConfig: {
        responseModalities: ['IMAGE'],
        responseFormat: {
          image: { 
            aspectRatio: geminiAspectRatio, 
            imageSize: 'IMAGE_SIZE_ONE_K'
          }
        }
      }
    }
  }
}];

// Parse Gemini response and extract generated image
const chatId = $node['Build Prompt'].json.chat_id;
const cleanCaption = $node['Build Prompt'].json.clean_caption || '';

try {
  const res = $input.first().json;

  // Check if blocked by safety settings
  const firstCandidate = res.candidates?.[0];
  const finishReason = firstCandidate?.finishReason || firstCandidate?.finish_reason;
  if (finishReason === 'SAFETY') {
    return [{ json: { success: false, chat_id: chatId, error_message: '⚠️ Không thể tạo ảnh thời trang do hình ảnh sản phẩm hoặc mô tả kích hoạt bộ lọc an toàn của AI. Vui lòng sử dụng ảnh sản phẩm rõ ràng hơn, góc chụp trực diện hoặc điều chỉnh lại mô tả của bạn.' } }];
  }

  const parts = firstCandidate?.content?.parts || [];
  const imgPart = parts.find(p => p.inlineData?.data || p.inline_data?.data);
  const imgData = imgPart?.inlineData || imgPart?.inline_data;

  if (!imgData?.data) {
    const textPart = parts.find(p => p.text);
    const apiError = textPart?.text || res.error?.message || 'Không có dữ liệu ảnh trả về từ API.';
    return [{ json: { success: false, chat_id: chatId, error_message: 'Gemini không trả về ảnh. Chi tiết: ' + apiError } }];
  }

  const mime = imgData.mimeType || imgData.mime_type || 'image/png';
  const ext = mime.includes('png') ? 'png' : 'jpg';
  const summary = cleanCaption || 'Ảnh sản phẩm thời trang chuyên nghiệp';

  return [{ 
    json: { success: true, chat_id: chatId, prompt_summary: summary, mime_type: mime },
    binary: { image: { data: imgData.data, mimeType: mime, fileName: 'fashion_product.' + ext, fileExtension: ext } }
  }];
} catch (err) {
  return [{ json: { success: false, chat_id: chatId, error_message: 'Lỗi xử lý phản hồi AI: ' + (err.message || String(err)) } }];
}

